// Recomienda TOP 3 parcelas disponibles segun forma_pago + presupuesto_clp|pie_clp.
// Reutiliza el mismo parser CSV que consultar_disponibilidad.
// Devuelve tool_output_text con el pitch + metadata cruda para el LLM.

const uf = $json;
const ufValor = uf && uf.serie && uf.serie[0] && typeof uf.serie[0].valor === 'number'
  ? uf.serie[0].valor
  : null;

const sheetItem = $('Fetch Google Sheet CSV').first().json;
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
if (!csvText || csvText.length < 100) {
  return [{ json: {
    ok: false,
    error: 'csv_fetch_failed',
    tool_output_text: 'No pude consultar el inventario en este momento. Dejame intentar en un minuto o paso tu caso al asesor.',
  } }];
}

const input = $('Execute Workflow Trigger').first().json || {};
const formaPago = (input.forma_pago || '').toString().toLowerCase().trim();
const presupuestoClp = Number(input.presupuesto_clp) || 0;
const pieClp = Number(input.pie_clp) || 0;
const tamanoPref = (input.tamano_preferido || '').toString().toLowerCase().trim();
const uso = (input.uso || '').toString().toLowerCase().trim();

function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const parseMoney = (s) => {
  if (!s) return null;
  const t = s.toString();
  if (t.includes('#DIV') || t.includes('#REF') || t.includes('#VALUE')) return null;
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseSize = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseIntSafe = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return e || 'desconocido';
};

const clpToUf = (clp) => (clp === null || !ufValor) ? null : Math.round((clp / ufValor) * 100) / 100;

const rows = parseCsv(csvText);
const parcelas = [];
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  const cuotaClp = parseMoney(r[11]);
  const p = {
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normalizeEstado(r[2]),
    tamano_m2: parseSize(r[3]),
    precio_contado: parseMoney(r[6]),
    descuento_pct: parseIntSafe(r[7]),
    precio_credito: parseMoney(r[9]),
    pie_minimo_50pct: parseMoney(r[10]),
    cuota_mensual_clp: cuotaClp,
    cuota_mensual_uf: clpToUf(cuotaClp),
  };
  if (p.estado === 'disponible') parcelas.push(p);
}

if (parcelas.length === 0) {
  return [{ json: {
    ok: true,
    total_candidatas: 0,
    recomendadas: [],
    tool_output_text: 'En este momento no tengo parcelas disponibles. Puedo pasar su caso al equipo para aviso cuando entre alguna. Le parece?',
  } }];
}

// Filtro por forma de pago
let candidatas = parcelas.slice();
if (formaPago === 'contado' && presupuestoClp > 0) {
  candidatas = candidatas.filter(p => p.precio_contado !== null && p.precio_contado <= presupuestoClp);
} else if (formaPago === 'credito' && pieClp > 0) {
  candidatas = candidatas.filter(p => p.pie_minimo_50pct !== null && p.pie_minimo_50pct <= pieClp);
}

// Si el filtro deja 0, relaja y toma las mas economicas igual (mejor ofrecer alternativas que decir 'nada')
let sinMatch = false;
if (candidatas.length === 0) {
  sinMatch = true;
  candidatas = parcelas.slice();
}

// Filtro por tamano preferido (soft)
if (tamanoPref.includes('1000') || tamanoPref.includes('hecta') || tamanoPref === 'grande') {
  const big = candidatas.filter(p => (p.tamano_m2 || 0) >= 7500);
  if (big.length >= 1) candidatas = big;
} else if (tamanoPref.includes('5000') || tamanoPref === 'chica' || tamanoPref === 'pequena') {
  const small = candidatas.filter(p => (p.tamano_m2 || 0) <= 6000);
  if (small.length >= 1) candidatas = small;
}

// Scoring: destacada, cercania al presupuesto/pie, tamano
candidatas.forEach(p => {
  let fit = 0;
  if (p.destacada) fit += 10;
  if (formaPago === 'contado' && presupuestoClp > 0 && p.precio_contado) {
    const dif = presupuestoClp - p.precio_contado;
    if (dif >= 0) fit += 20 - Math.min(20, Math.floor((dif / presupuestoClp) * 20));
  } else if (formaPago === 'credito' && pieClp > 0 && p.pie_minimo_50pct) {
    const dif = pieClp - p.pie_minimo_50pct;
    if (dif >= 0) fit += 20 - Math.min(20, Math.floor((dif / pieClp) * 20));
  } else {
    // Sin presupuesto: prioriza mas economicas
    fit += Math.max(0, 15 - Math.floor((p.precio_contado || 0) / 2000000));
  }
  if (uso === 'inversion' && p.tamano_m2 && p.tamano_m2 <= 6000) fit += 3;
  if ((uso === 'vivienda' || uso === 'segunda') && p.tamano_m2 && p.tamano_m2 >= 7500) fit += 3;
  p._fit = fit;
});

candidatas.sort((a, b) => b._fit - a._fit);
const top = candidatas.slice(0, 3);

const fmtClp = (n) => (n === null || n === undefined) ? '—' : `$${n.toLocaleString('es-CL')}`;
const fmtUf = (n) => (n === null || n === undefined) ? '—' : `${n.toFixed(2)} UF`;

function pitchLine(p) {
  const dest = p.destacada ? ' ⭐' : '';
  if (formaPago === 'credito') {
    return `Parcela ${p.numero}${dest} · ${p.tamano_m2} m² · pie 50% ${fmtClp(p.pie_minimo_50pct)} + 36 cuotas de ${fmtUf(p.cuota_mensual_uf)} (~${fmtClp(p.cuota_mensual_clp)}/mes al UF de hoy). Total crédito ${fmtClp(p.precio_credito)}.`;
  }
  return `Parcela ${p.numero}${dest} · ${p.tamano_m2} m² · contado ${fmtClp(p.precio_contado)} (dcto ${p.descuento_pct || 0}%).`;
}

const intro = sinMatch
  ? 'No tengo parcelas que calcen exacto con lo declarado, pero estas son las mejores alternativas cercanas:'
  : 'Basado en lo que me compartió, le recomiendo estas opciones:';

const text = `${intro}\n\n${top.map((p, i) => `${i + 1}. ${pitchLine(p)}`).join('\n')}\n\n¿Alguna le llama la atención para seguir afinando?`;

return [{ json: {
  ok: true,
  query: { forma_pago: formaPago, presupuesto_clp: presupuestoClp, pie_clp: pieClp, uso, tamano_preferido: tamanoPref },
  sin_match_estricto: sinMatch,
  uf_valor_clp: ufValor,
  total_candidatas: candidatas.length,
  recomendadas: top.map(p => ({
    numero: p.numero,
    destacada: p.destacada,
    tamano_m2: p.tamano_m2,
    precio_contado: p.precio_contado,
    precio_credito: p.precio_credito,
    pie_minimo_50pct: p.pie_minimo_50pct,
    cuota_mensual_uf: p.cuota_mensual_uf,
    cuota_mensual_clp: p.cuota_mensual_clp,
  })),
  tool_output_text: text,
} }];
